144	    @Override
145	    public Pagination<Entity> queryFailedEntities(EntityQueryDTO req) {
146	
147	        Specification<Entity> spec = (root, query, cb) -> {
148	            List<Predicate> predicates = new ArrayList<>();
149	
150	            if (req.getStage() != null && !req.getStage().isEmpty()) {
151	                predicates.add(cb.equal(root.get("processingStage"), req.getStage()));
152	            }
153	
154	            if (req.getCode() != null) {
155	                predicates.add(cb.equal(root.get("processingCode"), req.getCode()));
156	            } else {
157	                predicates.add(cb.notEqual(root.get("processingCode"), 0));
158	            }
159	
160	            return cb.and(predicates.toArray(new Predicate[0]));
161	        };
162	
163	        String sortKey = req.getSortKey();
164	        boolean asc = "asc".equalsIgnoreCase(req.getSortOrder());
165	
166	        if (sortKey == null || sortKey.isEmpty()) {
167	            sortKey = "createdAt";
168	        }
169	
170	        String sortProperty;
171	        switch (sortKey) {
172	            case "processingStage":
173	                sortProperty = "processingStage";
174	                break;
175	            case "type":
176	                sortProperty = "type";
177	                break;
178	            case "createdAt":
179	            default:
180	                sortProperty = "createdAt";
181	                break;
182	        }
183	
184	        Sort sort = Sort.by(asc ? Sort.Direction.ASC : Sort.Direction.DESC, sortProperty);
185	        Pageable pageable = PageRequest.of(
186	                Math.max(0, req.getPageNum() - 1),
187	                req.getPageSize(),
188	                sort
189	        );
190	
191	        Page<Entity> page = entityRepository.findAll(spec, pageable);
192	
193	        return Pagination.<Entity>builder()
194	                .list(page.getContent())
195	                .totalRecords(page.getTotalElements())
196	                .totalPages(page.getTotalPages())
197	                .pageNum(page.getNumber() + 1)
198	                .pageSize(page.getSize())
199	                .build();
200	    }
